#pragma once

#include <cstdint>

// <source_location> is a C++20 standard-library header, but not every C++20
// toolchain actually ships it. The OpenHarmony (OHOS) NDK in particular links
// against a libc++ that does not provide <source_location> at all, so an
// unconditional `#include <source_location>` fails to build there.
//
// Adding a partial definition to namespace std would be undefined behaviour
// (the standard reserves std for the implementation), so this header exposes a
// single mbgl-owned type, mbgl::util::SourceLocation. It aliases
// std::source_location when the header is available and otherwise falls back to
// a small replacement that mirrors its observable interface. Call sites should
// always use mbgl::util::SourceLocation together with SourceLocation::current()
// so the file/line/function diagnostics they emit stay useful on every
// platform.
#if __has_include(<source_location>)
#include <source_location>
#endif

namespace mbgl {
namespace util {

#if __has_include(<source_location>)

using SourceLocation = std::source_location;

#else

// Minimal std::source_location-compatible type. current() forwards
// __builtin_LINE / __builtin_FILE / __builtin_FUNCTION as default arguments so,
// exactly like std::source_location::current(), it captures the location of the
// caller rather than this header. column() is not reported by the fallback as
// the portable builtins do not give us a column on every supported compiler.
struct SourceLocation {
    constexpr SourceLocation() noexcept = default;
    constexpr SourceLocation(const char* fileName, const char* functionName, std::uint_least32_t line) noexcept
        : fileName_(fileName),
          functionName_(functionName),
          line_(line) {}

    static constexpr SourceLocation current(const char* fileName = __builtin_FILE(),
                                            const char* functionName = __builtin_FUNCTION(),
                                            std::uint_least32_t line = __builtin_LINE()) noexcept {
        return SourceLocation(fileName, functionName, line);
    }

    constexpr std::uint_least32_t line() const noexcept { return line_; }
    constexpr std::uint_least32_t column() const noexcept { return 0; }
    constexpr const char* file_name() const noexcept { return fileName_; }
    constexpr const char* function_name() const noexcept { return functionName_; }

private:
    const char* fileName_ = "";
    const char* functionName_ = "";
    std::uint_least32_t line_ = 0;
};

#endif

} // namespace util
} // namespace mbgl

