#define SYM_GUARD_VALUE(N) std::uint64_t check##N = checkVal;
#else
#define SYM_GUARD_VALUE(N)
#endif

// mbgl::util::SourceLocation is std::source_location when the standard library
// provides <source_location>, and a portable fallback otherwise (e.g. on
// OpenHarmony, whose libc++ lacks the header). Either way current() resolves at
// the call site, so diagnostics keep their file/line/function information.
#if MLN_SYMBOL_GUARDS
#define SYM_GUARD_LOC (::mbgl::util::SourceLocation::current())
#else
#define SYM_GUARD_LOC
#endif

