#include <mbgl/util/source_location.hpp>
#include <cassert>
#include <cstdio>
#include <cstring>

static const char* sink;

__attribute__((noinline)) void record(const mbgl::util::SourceLocation& loc) {
    sink = loc.function_name();
    assert(loc.line() > 0);
    assert(std::strstr(loc.file_name(), "sl_test.cpp") != nullptr);
}

int main() {
    auto loc = mbgl::util::SourceLocation::current();
    record(loc);
    // Default-constructed is well-defined and empty.
    mbgl::util::SourceLocation empty{};
    (void)empty.file_name();
    (void)empty.line();
    (void)empty.column();
    (void)empty.function_name();
    std::printf("OK: current line=%u col=%u file=%s fn=%s\n",
                loc.line(), loc.column(), loc.file_name(), loc.function_name());
    return 0;
}
EOF
