// Replicate the OpenHarmony fallback branch exactly.
namespace mbgl { namespace util {
struct SourceLocation {
    constexpr SourceLocation() noexcept = default;
    constexpr SourceLocation(const char* fileName, const char* functionName, std::uint_least32_t line) noexcept
        : fileName_(fileName), functionName_(functionName), line_(line) {}
    static constexpr SourceLocation current(const char* fileName = __builtin_FILE(),
                                            const char* functionName = __builtin_FUNCTION(),
                                            std::uint_least32_t line = __builtin_LINE()) noexcept {
        return SourceLocation(fileName, functionName, line);
    }
    constexpr std::uint_least32_t line() const noexcept { return line_; }
    constexpr std::uint_least32_t column() const noexcept { return 0; }
    constexpr const char* file_name() const noexcept { return fileName_; }
    constexpr const char* function_name() const noexcept { return functionName_; }
private:
    const char* fileName_ = "";
    const char* functionName_ = "";
    std::uint_least32_t line_ = 0;
};
}}

